def get_closest_vowel(word):
    vowels = set('aeiouAEIOU')
    n = len(word)

    # Iterate from right to left (excluding boundaries)
    for i in range(n - 2, 0, -1):
        if word[i] in vowels:
            # Check flanking consonants
            if word[i - 1] not in vowels and word[i + 1] not in vowels:
                return word[i]
    return ""
